public List<Object[]> getGL_SCHArchival() {
			List<Object[]> archivalList = new ArrayList<>();
			

			try {
				
				List<GL_SCH_Archival_Summary_Entity1> repoData =
						getarchivaldatabydateListWithVersion1();

				if (repoData != null && !repoData.isEmpty()) {
					for (GL_SCH_Archival_Summary_Entity1 entity : repoData) {
						Object[] row = new Object[] {
								entity.getREPORT_DATE(), 
								entity.getREPORT_VERSION(), 
								 entity.getREPORT_RESUBDATE()
						};
						archivalList.add(row);
					}

					System.out.println("Fetched " + archivalList.size() + " archival records");
					GL_SCH_Archival_Summary_Entity1 first = repoData.get(0);
					System.out.println("Latest archival version: " + first.getREPORT_VERSION());
				} else {
					System.out.println("No archival data found.");
				}

			} catch (Exception e) {
				System.err.println("Error fetching  GL_SCH  Archival data: " + e.getMessage());
				e.printStackTrace();
			}

			return archivalList;
		}
